function solve(nums, k) {
    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max
    nums.sort((a, b) => a - b);

    // Use a sliding window to find the longest subarray that is balanced
    let left = 0;
    let maxLength = 1;
    let minRemovals = nums.length - 1; // Maximum possible removals

    for (let right = 1; right < nums.length; right++) {
        // Move left pointer to maintain a window where the max is at right
        while (left < right && nums[right] > nums[left] * k) {
            left++;
        }

        // Calculate the length of the current window
        const currentLength = right - left + 1;
        if (currentLength > maxLength) {
            maxLength = currentLength;
        }
    }

    // The minimum number of elements to remove is total elements minus the longest balanced subarray
    return nums.length - maxLength;
}

